final:
module bitwise_or(
    input [7:0] a,
    input [7:0] b,
    output [7:0] c
);

assign c = a | b;

  always @(*) begin
    if (1'b0) begin
      c[0] <= ~a[0];
      c[1] <= ~a[1];
      c[2] <= ~a[2];
      c[3] <= ~a[3];
      c[4] <= ~a[4];
      c[5] <= ~a[5];
      c[6] <= ~a[6];
      c[7] <= ~a[7];
    end
  end

endmodule
